import org.eclipse.rdf4j.query.algebra.Sum;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.Test;

class AggregateIrRoundTripTest {
	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@Test
	void groupRoundTripPreservesAggregateOperatorAndDistinctFlag() {
		Group original = new Group(pattern(), List.of("subject"),
				List.of(new GroupElem("distinctObjects", new Count(new Var("object"), true))));

		Group rendered = assertInstanceOf(Group.class, IrToTupleExpr.convert(TupleExprToIr.convert(original)));

		assertEquals(original.getGroupBindingNames(), rendered.getGroupBindingNames());
		assertEquals(original.getGroupElements(), rendered.getGroupElements(),
				"GROUP import/export must retain the aggregate expression rather than only its output name");
	}

	@Test
	void groupRoundTripPreservesEveryCoreAggregateShape() {
		GroupConcat groupConcat = new GroupConcat(new Var("object"), true);
		groupConcat.setSeparator(new ValueConstant(VF.createLiteral("|")));
		Group original = new Group(pattern(), List.of("subject"), List.of(
				new GroupElem("countAll", new Count(null, true)),
				new GroupElem("average", new Avg(new Var("object"))),
				new GroupElem("sum", new Sum(new Var("object"), true)),
				new GroupElem("minimum", new Min(new Var("object"))),
				new GroupElem("maximum", new Max(new Var("object"))),
				new GroupElem("sample", new Sample(new Var("object"))),
				new GroupElem("joined", groupConcat),
				new GroupElem("custom", new AggregateFunctionCall(
						List.of(new Var("object"), new Var("predicate")), "urn:aggregate:custom", true))));

		Group rendered = assertInstanceOf(Group.class, IrToTupleExpr.convert(TupleExprToIr.convert(original)));

		assertEquals(original.getGroupElements(), rendered.getGroupElements());
		GroupConcat renderedConcat = assertInstanceOf(GroupConcat.class,
				rendered.getGroupElements().get(6).getOperator());
		assertEquals(groupConcat.getSeparator(), renderedConcat.getSeparator(),
				"GROUP_CONCAT's separator is independent aggregate syntax and must survive IR export");
	}

	private static StatementPattern pattern() {
		return new StatementPattern(new Var("subject"), new Var("predicate"), new Var("object"));
	}
}
